1	import { useState, useEffect } from "react";
2	import SuccessOverlay from "@/components/ui/SuccessOverlay";
3	import { supabase } from "@/integrations/supabase/client";
4	import { Button } from "@/components/ui/button";
5	import { Textarea } from "@/components/ui/textarea";
6	import {
7	  Dialog,
8	  DialogContent,
9	  DialogHeader,
10	  DialogTitle,
11	} from "@/components/ui/dialog";
12	import { FileSignature } from "lucide-react";
13	import { toast } from "sonner";
14	
15	interface CreateContractDialogProps {
16	  open: boolean;
17	  onOpenChange: (open: boolean) => void;
18	  editingContract?: any;
19	  onSuccess: () => void;
20	  onCreated?: (id: string) => void;
21	  kiraContext?: Record<string, unknown> | null;
22	}
23	
24	const CreateContractDialog = ({
25	  open,
26	  onOpenChange,
27	  editingContract,
28	  onSuccess,
29	  onCreated,
30	  kiraContext,
31	}: CreateContractDialogProps) => {
32	  const [loading, setLoading] = useState(false);
33	  const [showSuccess, setShowSuccess] = useState(false);
34	  const [content, setContent] = useState("");
35	
36	  useEffect(() => {
37	    if (!open) return;
38	    if (editingContract) {
39	      setContent(editingContract.content ?? "");
40	    } else if (kiraContext) {
41	      if (kiraContext.content) setContent(kiraContext.content as string);
42	    } else {
43	      setContent("");
44	    }
45	  }, [editingContract, kiraContext, open]);
46	
47	  const handleSubmit = async () => {
48	    setLoading(true);
49	    try {
50	      const { data: { session } } = await supabase.auth.getSession();
51	      if (!session) { toast.error("Please log in"); return; }
52	
53	      const autoTitle = `Canvas – ${new Date().toLocaleDateString()}`;
54	      const contractData = {
55	        user_id: session.user.id,
56	        title: editingContract?.title?.trim() || autoTitle,
57	        client_name: editingContract?.client_name?.trim() || "",
58	        client_email: editingContract?.client_email?.trim() || null,
59	        contract_type: "custom",
60	        content: content || null,
61	      };
62	
63	      if (editingContract) {
64	        const { error } = await supabase
65	          .from("canvases")
66	          .update(contractData)
67	          .eq("id", editingContract.id);
68	        if (error) throw error;
69	        onSuccess();
70	        onOpenChange(false);
71	        toast.success("Canvas updated");
72	      } else {
73	        const { data: created, error } = await supabase
74	          .from("canvases")
75	          .insert(contractData)
76	          .select("id")
77	          .single();
78	        if (error) throw error;
79	        if (created?.id) onCreated?.(created.id);
80	        onOpenChange(false);
81	        setShowSuccess(true);
82	      }
83	    } catch (error: any) {
84	      if (error.message?.includes("contract_limit_reached")) {
85	        toast.error("Monthly limit reached", {
86	          description: "Free plan allows 2 Canvas per month. Upgrade to Pro for unlimited.",
87	        });
88	      } else {
89	        toast.error(error.message || "Failed to save Canvas");
90	      }
91	    } finally {
92	      setLoading(false);
93	    }
94	  };
95	
96	  return (
97	    <>
98	      <SuccessOverlay
99	        show={showSuccess}
100	        title="Canvas Created"
101	        subtitle="Your Canvas is ready to sign"
102	        onComplete={() => { setShowSuccess(false); onSuccess(); }}
103	      />
104	
105	      <Dialog open={open} onOpenChange={onOpenChange}>
106	        <DialogContent className="w-[calc(100vw-16px)] sm:max-w-2xl lg:max-w-3xl max-h-[90vh] overflow-hidden flex flex-col p-0 gap-0 rounded-2xl">
107	          {/* Header */}
108	          <div className="px-4 sm:px-6 pt-5 pb-4 border-b border-border/50 flex-shrink-0">
109	            <DialogHeader>
110	              <DialogTitle className="font-vollkorn text-xl flex items-center gap-2">
111	                <div className="w-8 h-8 rounded-xl bg-primary/10 flex items-center justify-center">
112	                  <FileSignature className="h-4 w-4 text-primary" />
113	                </div>
114	                {editingContract ? "Edit Canvas" : "New Canvas"}
115	              </DialogTitle>
116	            </DialogHeader>
117	          </div>
118	
119	          {/* Canvas */}
120	          <div className="flex-1 overflow-y-auto px-4 sm:px-6 py-4 sm:py-5">
121	            <Textarea
122	              value={content}
123	              onChange={(e) => setContent(e.target.value)}
124	              placeholder="Start writing your Canvas here…"
125	              className="rounded-xl font-mono text-sm leading-relaxed min-h-[520px] resize-none bg-background border-border/60 focus:border-primary/30 focus-visible:ring-primary/20"
126	              spellCheck={false}
127	              autoFocus
128	            />
129	          </div>
130	
131	          {/* Footer */}
132	          <div className="px-4 sm:px-6 py-4 border-t border-border/50 flex items-center justify-between bg-muted/20 flex-shrink-0">
133	            <Button variant="ghost" onClick={() => onOpenChange(false)} className="rounded-xl">
134	              Cancel
135	            </Button>
136	            <Button
137	              onClick={handleSubmit}
138	              disabled={loading}
139	              className="rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20"
140	            >
141	              {loading ? "Saving…" : editingContract ? "Update Canvas" : "Save Canvas"}
142	            </Button>
143	          </div>
144	        </DialogContent>
145	      </Dialog>
146	    </>
147	  );
148	};
149	
150	export default CreateContractDialog;
