54	interface Contract {
55	  id: string;
56	  title: string;
57	  client_name: string;
58	  client_email: string | null;
59	  contract_type: string;
60	  status: string;
61	  start_date: string | null;
62	  end_date: string | null;
63	  value: number | null;
64	  currency: string;
65	  created_at: string;
66	  creator_signature: string | null;
67	  client_signature: string | null;
68	  content: string | null;
69	  deliverables: string[] | null;
70	  payment_terms: string | null;
71	  exclusivity: boolean | null;
72	  exclusivity_details: string | null;
73	  usage_rights: string | null;
74	  termination_clause: string | null;
75	}
