77	const contractTypeConfig: Record<string, { label: string; icon: string; gradient: string }> = {
78	  sponsorship: { label: "Sponsorship", icon: "💎", gradient: "from-violet-500/10 to-purple-500/5" },
79	  content_creation: { label: "Content", icon: "🎬", gradient: "from-blue-500/10 to-cyan-500/5" },
80	  brand_ambassador: { label: "Ambassador", icon: "🤝", gradient: "from-amber-500/10 to-orange-500/5" },
81	  ugc: { label: "UGC", icon: "📱", gradient: "from-green-500/10 to-emerald-500/5" },
82	  affiliate: { label: "Affiliate", icon: "🔗", gradient: "from-pink-500/10 to-rose-500/5" },
83	  custom: { label: "Custom", icon: "📄", gradient: "from-slate-500/10 to-gray-500/5" },
84	  uploaded: { label: "Uploaded", icon: "📎", gradient: "from-indigo-500/10 to-blue-500/5" },
85	};
86	
87	const statusConfig: Record<string, { label: string; color: string; bg: string; icon: React.ReactNode }> = {
88	  draft: { label: "Draft", color: "text-muted-foreground", bg: "bg-muted", icon: <FileText className="h-3 w-3" /> },
89	  sent: { label: "Sent", color: "text-blue-600 dark:text-blue-400", bg: "bg-blue-500/10", icon: <Send className="h-3 w-3" /> },
90	  signed: { label: "Signed", color: "text-emerald-600 dark:text-emerald-400", bg: "bg-emerald-500/10", icon: <FileSignature className="h-3 w-3" /> },
91	  active: { label: "Active", color: "text-green-600 dark:text-green-400", bg: "bg-green-500/10", icon: <CheckCircle2 className="h-3 w-3" /> },
92	  completed: { label: "Completed", color: "text-purple-600 dark:text-purple-400", bg: "bg-purple-500/10", icon: <CheckCircle2 className="h-3 w-3" /> },
93	  cancelled: { label: "Cancelled", color: "text-destructive", bg: "bg-destructive/10", icon: <XCircle className="h-3 w-3" /> },
94	};
95	
96	const ContractsTab = ({ workspaceId }: { workspaceId?: string } = {}) => {
97	  const [contracts, setContracts] = useState<Contract[]>([]);
98	  const [loading, setLoading] = useState(true);
99	  const [searchQuery, setSearchQuery] = useState("");
100	  const [statusFilter, setStatusFilter] = useState("all");
101	  const [sortBy, setSortBy] = useState<"newest" | "oldest" | "value">("newest");
102	  const { limits, isFree } = useSubscription();
103	  const [createDialogOpen, setCreateDialogOpen] = useState(false);
104	  const [editingContract, setEditingContract] = useState<Contract | null>(null);
105	  const [previewContract, setPreviewContract] = useState<Contract | null>(null);
106	  const [uploadDialogOpen, setUploadDialogOpen] = useState(false);
107	  const [renamingId, setRenamingId] = useState<string | null>(null);
108	  const [renameValue, setRenameValue] = useState("");
109	
110	  const fetchContracts = async () => {
111	    const { data: { session } } = await supabase.auth.getSession();
112	    if (!session) return;
113	
114	    if (workspaceId) {
115	      const { data: msgs } = await supabase
116	        .from("chat_messages")
117	        .select("contract_id")
118	        .eq("room_id", workspaceId)
119	        .not("contract_id", "is", null);
120	      const ids = [...new Set((msgs || []).map((m: any) => m.contract_id).filter(Boolean))];
121	      if (ids.length === 0) { setContracts([]); setLoading(false); return; }
122	      const { data, error } = await supabase.from("canvases").select("*").in("id", ids).order("created_at", { ascending: false });
123	      if (error) { toast.error("Failed to load Canvas"); return; }
124	      setContracts(data || []);
125	      setLoading(false);
126	      return;
127	    }
128	
129	    const { data, error } = await supabase
130	      .from("canvases")
131	      .select("*")
132	      .eq("user_id", session.user.id)
133	      .order("created_at", { ascending: false });
134	
135	    if (error) {
136	      toast.error("Failed to load Canvas");
137	      return;
138	    }
139	
140	    setContracts(data || []);
141	    setLoading(false);
142	  };
143	
144	  useEffect(() => {
145	    fetchContracts();
146	  }, [workspaceId]);
147	
148	  const handleRename = async (id: string) => {
149	    const trimmed = renameValue.trim();
150	    if (!trimmed) { toast.error("Title cannot be empty"); return; }
151	    const { error } = await supabase.from("canvases").update({ title: trimmed }).eq("id", id);
152	    if (error) { toast.error("Failed to rename Canvas"); return; }
153	    setRenamingId(null);
154	    fetchContracts();
155	    toast.success("Canvas renamed");
156	  };
157	
158	  const handleDelete = async (id: string) => {
159	    const { error } = await supabase.from("canvases").delete().eq("id", id);
160	    if (error) {
161	      toast.error("Failed to delete Canvas");
162	      return;
163	    }
164	    toast.success("Canvas deleted");
165	    fetchContracts();
166	  };
167	
168	  const handleDuplicate = async (contract: Contract) => {
169	    const { data: { session } } = await supabase.auth.getSession();
170	    if (!session) return;
171	
172	    const { error } = await supabase.from("canvases").insert({
173	      user_id: session.user.id,
174	      title: `${contract.title} (Copy)`,
175	      client_name: contract.client_name,
176	      client_email: contract.client_email,
177	      contract_type: contract.contract_type,
178	      content: contract.content,
179	      deliverables: contract.deliverables,
180	      payment_terms: contract.payment_terms,
181	      exclusivity: contract.exclusivity,
182	      exclusivity_details: contract.exclusivity_details,
183	      usage_rights: contract.usage_rights,
184	      termination_clause: contract.termination_clause,
185	      value: contract.value,
186	      currency: contract.currency,
187	      status: "draft",
188	    });
189	
190	    if (error) {
191	      toast.error("Failed to duplicate Canvas");
192	      return;
193	    }
194	    toast.success("Canvas duplicated");
195	    fetchContracts();
196	  };
197	
198	  const handleStatusChange = async (id: string, status: string) => {
199	    const { error } = await supabase
200	      .from("contracts")
201	      .update({ status })
202	      .eq("id", id);
203	
204	    if (error) {
205	      toast.error("Failed to update status");
206	      return;
207	    }
208	    toast.success(`Status updated to ${status}`);
209	    fetchContracts();
210	  };
211	
212	  const handleFileUpload = async (file: File, contractType: string, title: string) => {
213	    const { data: { session } } = await supabase.auth.getSession();
214	    if (!session) return;
215	
216	    const fileExt = file.name.split(".").pop()?.toLowerCase();
217	    
218	    let content = "";
219	
220	    // For text-based files, read the content directly for editing
221	    if (fileExt === "txt" || fileExt === "md") {
222	      content = await file.text();
223	    } else {
224	      // For PDF, DOCX, etc. — upload to storage and create editable content
225	      const storagePath = `${session.user.id}/${Date.now()}-${file.name}`;
226	      
227	      const { error: uploadError } = await supabase.storage
228	        .from("contract-uploads")
229	        .upload(storagePath, file);
230	
231	      if (uploadError) {
232	        toast.error("Failed to upload file: " + uploadError.message);
233	        return;
234	      }
235	
236	      content = `[Original file: ${file.name}]\n[File type: ${file.type || fileExt}]\n[Uploaded: ${new Date().toLocaleString()}]\n\n---\n\nYou can edit this contract content below. The original document has been securely stored.\n\n---\n\n[Add or paste your contract terms here]`;
237	    }
238	
239	    const { data, error } = await supabase.from("canvases").insert({
240	      user_id: session.user.id,
241	      title,
242	      client_name: "To be specified",
243	      contract_type: contractType,
244	      content,
245	      status: "draft",
246	      currency: "KES",
247	    }).select().single();
248	
249	    if (error) {
250	      toast.error("Failed to create contract record");
251	      return;
252	    }
253	
254	    toast.success("Canvas uploaded! You can now edit all details.");
255	    fetchContracts();
256	    
257	    // Open the edit dialog immediately so user can fill in details
258	    if (data) {
259	      setEditingContract(data as Contract);
260	    }
261	  };
262	
263	  const formatCurrency = (amount: number | null, currency: string) => {
264	    if (!amount) return "—";
265	    return new Intl.NumberFormat("en-KE", {
266	      style: "currency",
267	      currency: currency || "KES",
268	    }).format(amount);
269	  };
270	
271	  const filteredContracts = contracts
272	    .filter((contract) => {
273	      const matchesSearch = contract.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
274	        contract.client_name.toLowerCase().includes(searchQuery.toLowerCase());
275	      const matchesStatus = statusFilter === "all" || contract.status === statusFilter;
276	      return matchesSearch && matchesStatus;
277	    })
278	    .sort((a, b) => {
279	      if (sortBy === "value") return (Number(b.value) || 0) - (Number(a.value) || 0);
280	      if (sortBy === "oldest") return new Date(a.created_at).getTime() - new Date(b.created_at).getTime();
281	      return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
282	    });
283	
284	  const stats = {
285	    total: contracts.length,
286	    active: contracts.filter((c) => c.status === "active" || c.status === "signed").length,
287	    pending: contracts.filter((c) => c.status === "sent" || c.status === "draft").length,
288	    totalValue: contracts.filter(c => c.status !== "cancelled").reduce((acc, c) => acc + (Number(c.value) || 0), 0),
289	  };
290	
291	  if (loading) {
292	    return (
293	      <div className="mx-auto w-full max-w-6xl space-y-8 p-4 md:p-8">
294	        <div className="animate-pulse space-y-8">
295	          <div className="h-10 bg-muted rounded-2xl w-1/3" />
296	          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
297	            {[...Array(4)].map((_, i) => (
298	              <div key={i} className="h-24 bg-muted rounded-2xl" />
299	            ))}
300	          </div>
301	          <div className="h-12 bg-muted rounded-2xl" />
302	          {[...Array(3)].map((_, i) => (
303	            <div key={i} className="h-20 bg-muted rounded-2xl" />
304	          ))}
305	        </div>
306	      </div>
307	    );
308	  }
309	
310	  return (
311	    <div className="mx-auto w-full max-w-6xl min-w-0 space-y-6 p-4 md:p-8 xl:max-w-7xl">
312	
313	      {/* Header — Clean & Minimal */}
314	      <motion.div 
315	        initial={{ opacity: 0, y: 8 }}
316	        animate={{ opacity: 1, y: 0 }}
317	        className="flex flex-col md:flex-row md:items-end justify-between gap-4"
318	      >
319	        <div>
320	          <h2 className="font-vollkorn text-2xl md:text-4xl font-bold text-foreground tracking-tight">
321	            Canvas
322	          </h2>
323	          <p className="text-sm text-muted-foreground mt-1">
324	            Professional agreements, e-signatures & document management
325	          </p>
326	        </div>
327	        <div className="flex items-center gap-2 w-full md:w-auto">
328	          <Button
329	            variant="outline"
330	            onClick={() => setUploadDialogOpen(true)}
331	            className="gap-2 h-10 rounded-xl border-dashed hover:border-bronze/50 hover:bg-bronze/5 transition-all flex-1 md:flex-none"
332	          >
333	            <Upload className="h-4 w-4" />
334	            <span>Upload</span>
335	          </Button>
336	          <Button
337	            // onClick={() => setCreateDialogOpen(true)}
338	            onClick={async () => {
339	              if (isFree) {
340	                const { count } = await supabase
341	                  .from("canvases")
342	                  .select("*", { count: "exact", head: true });
343	                if ((count || 0) >= limits.canvasesPerMonth) {
344	                  toast.error("You've reached your free plan limit of 2 Canvas. Upgrade to Pro for unlimited Canvas.");
345	                return;
346	              }
347	            }
348	            setCreateDialogOpen(true);
349	          }}
350	            className="gap-2 h-10 rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/20 transition-all hover:shadow-xl hover:shadow-primary/30 flex-1 md:flex-none"
351	          >
352	            <Plus className="h-4 w-4" />
353	            New Canvas
354	          </Button>
355	        </div>
356	      </motion.div>
357	
358	      {/* Stats */}
359	      <motion.div
360	        initial={{ opacity: 0, y: 12 }}
361	        animate={{ opacity: 1, y: 0 }}
362	        transition={{ delay: 0.05 }}
363	        className="grid grid-cols-2 gap-3 xl:grid-cols-4"
364	      >
365	        {[
366	          { label: "Total", value: stats.total, isCurrency: false, icon: <File className="h-4 w-4" />, iconBg: "bg-primary/10 text-primary" },
367	          { label: "Active", value: stats.active, isCurrency: false, icon: <CheckCircle2 className="h-4 w-4" />, iconBg: "bg-emerald-500/10 text-emerald-500" },
368	          { label: "Pending", value: stats.pending, isCurrency: false, icon: <Clock className="h-4 w-4" />, iconBg: "bg-amber-500/10 text-amber-500" },
369	          { label: "Value", value: stats.totalValue, isCurrency: true, icon: <TrendingUp className="h-4 w-4" />, iconBg: "bg-blue-500/10 text-blue-500" },
370	        ].map((stat) => (
371	          <div
372	            key={stat.label}
373	            className="flex items-center gap-2.5 p-4 rounded-2xl border border-border/50 bg-card overflow-hidden"
374	          >
375	            <div className={`w-8 h-8 rounded-xl flex items-center justify-center flex-shrink-0 ${stat.iconBg}`}>
376	              {stat.icon}
377	            </div>
378	            <div className="min-w-0">
379	              <p className="text-xl font-bold text-foreground leading-none md:text-2xl truncate">
380	                {stat.isCurrency ? formatCurrency(Number(stat.value), "KES") : stat.value}
381	              </p>
382	              <p className="text-xs text-muted-foreground mt-0.5">{stat.label}</p>
383	            </div>
384	          </div>
385	        ))}
386	      </motion.div>
387	
388	      {/* Search & Filters — Unified Bar */}
389	      <motion.div
390	        initial={{ opacity: 0, y: 12 }}
391	        animate={{ opacity: 1, y: 0 }}
392	        transition={{ delay: 0.1 }}
393	        className="flex flex-col gap-2"
394	      >
395	        <div className="relative">
396	          <Search className="absolute left-3.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
397	          <Input
398	            placeholder="Search Canvas, clients..."
399	            value={searchQuery}
400	            onChange={(e) => setSearchQuery(e.target.value)}
401	            className="pl-10 h-10 rounded-xl bg-muted/50 border-0 focus:bg-background focus:ring-1 focus:ring-primary/20 transition-all"
402	          />
403	        </div>
404	        <div className="flex gap-2">
405	          <Select value={statusFilter} onValueChange={setStatusFilter}>
406	            <SelectTrigger className="flex-1 h-10 rounded-xl bg-muted/50 border-0">
407	              <Filter className="h-3.5 w-3.5 mr-1.5 text-muted-foreground flex-shrink-0" />
