71	// AppContent lives inside BrowserRouter so routing hooks are available.
72	// useInitializeE2EE is called HERE — at the very top of this component,
73	// before any conditional returns — so React's rules of hooks are never violated.
74	function AppContent() {
75	  const [userId, setUserId] = useState("");
76	  const [maintenance, setMaintenance] = useState(false);
77	  const location = useLocation();
78	
79	  // MUST be called before any early returns.
80	  // Receives "" until the auth state resolves, then fires the full init flow.
81	  const {
82	    error: e2eeError,
83	    needsRecoveryPassword,
84	    needsMigration,
