86	    clearMigrationFlag,
87	  } = useInitializeE2EE(userId);
88	
89	  const [migrationDialogOpen, setMigrationDialogOpen] = useState(false);
90	
91	  // Open the migration dialog as soon as the flag is raised, but only once per session.
92	  useEffect(() => {
93	    if (needsMigration) setMigrationDialogOpen(true);
94	  }, [needsMigration]);
95	
96	  useEffect(() => {
97	    // onAuthStateChange fires immediately with the current session
98	    // (INITIAL_SESSION event) AND fires again on every sign-in / sign-out.
99	    // This is more reliable than getSession() which can return null on the
100	    // first tick in OAuth / server-redirect flows.
101	    const {
102	      data: { subscription },
103	    } = supabase.auth.onAuthStateChange((_event, session) => {
104	      setUserId(session?.user?.id ?? "");
105	    });
106	
107	    return () => subscription.unsubscribe();
108	  }, []);
109	
110	  // Background maintenance check — never blocks render
111	  useEffect(() => {
112	    supabase.from("app_settings" as any)
113	      .select("value")
114	      .eq("key", "maintenance_mode")
