116	      .then(({ data }) => {
117	        if ((data as any)?.value === "true") setMaintenance(true);
118	      });
119	  }, []);
120	
121	  // Admin path always bypasses maintenance so the toggle can be turned off
122	  if (maintenance && !location.pathname.startsWith("/admin")) return <MaintenancePage />;
123	
124	  return (
125	    <>
126	      <ScrollToTop />
127	      <CookieConsent />
128	
129	      {/* Non-dismissible: shown on a new device when a v2 backup exists */}
130	      <RecoveryPasswordModal
