132	        error={e2eeError}
133	        onSubmit={provideRecoveryPassword}
134	      />
135	
136	      {/* Dismissible: nudges v1 users and new users to set a recovery password */}
137	      <SetRecoveryPasswordDialog
138	        open={migrationDialogOpen}
139	        userId={userId}
140	        onOpenChange={setMigrationDialogOpen}
141	        onComplete={clearMigrationFlag}
142	      />
143	
144	      <Suspense fallback={<PageLoader />}>
145	        <Routes>
146	          {/* Public routes */}
147	          <Route path="/" element={<PublicPageWrapper><Home /></PublicPageWrapper>} />
148	          <Route path="/auth" element={<PublicPageWrapper><Auth /></PublicPageWrapper>} />
149	          <Route path="/auth/callback" element={<AuthCallback />} />
150	          <Route path="/reset-password" element={<PublicPageWrapper><ResetPassword /></PublicPageWrapper>} />
151	          <Route path="/pricing" element={<PublicPageWrapper><Pricing /></PublicPageWrapper>} />
152	          <Route path="/about" element={<PublicPageWrapper><About /></PublicPageWrapper>} />
153	          <Route path="/app/about" element={<AppLayout><About isEmbedded /></AppLayout>} />
154	          <Route path="/privacy-policy" element={<AppLayout><PrivacyPolicy /></AppLayout>} />
155	          <Route path="/terms-of-service" element={<AppLayout><TermsOfService /></AppLayout>} />
156	          <Route path="/cookie-policy" element={<AppLayout><CookiePolicy /></AppLayout>} />
157	          <Route path="/user-type-selection" element={<Navigate to="/auth" replace />} />
158	          <Route path="/signup/creator" element={<Navigate to="/auth?mode=signup" replace />} />
159	          <Route path="/signup/brand" element={<Navigate to="/auth?mode=signup" replace />} />
160	          <Route path="/:username" element={<PublicPageWrapper><PublicProfile /></PublicPageWrapper>} />
161	
162	          {/* Protected routes */}
163	          <Route path="/dashboard" element={<Navigate to="/kira" replace />} />
164	          <Route path="/kira" element={<ProtectedRoute><AppLayout><Kira /></AppLayout></ProtectedRoute>} />
165	          <Route path="/crevia-link" element={<ProtectedRoute><AppLayout><CreviaLink /></AppLayout></ProtectedRoute>} />
166	          <Route path="/crevia-studio" element={<ProtectedRoute><AppLayout><CreviaStudio /></AppLayout></ProtectedRoute>} />
167	          <Route path="/crevia-invoice" element={<ProtectedRoute><AppLayout><CreviaInvoice /></AppLayout></ProtectedRoute>} />
