53	  const secondPayment = totalAmount / 2;
54	
55	  const creatorName = application.creator_profiles?.profiles?.display_name || 
56	    application.creator_profiles?.profiles?.handle || "Creator";
57	
58	  const handleProceedToPayment = () => {
59	    setStep("payment");
60	  };
61	
62	  const handleFundEscrow = async () => {
63	    if (paymentMethod === "mpesa" && !mpesaPhone) {
64	      toast.error("Please enter your M-Pesa phone number");
65	      return;
66	    }
67	
68	    setStep("processing");
69	    setProcessing(true);
70	
71	    try {
72	      const { data: { user } } = await supabase.auth.getUser();
73	      if (!user) throw new Error("Not authenticated");
74	
75	      // Simulate payment processing
76	      await new Promise(resolve => setTimeout(resolve, 2500));
77	
78	      // Create escrow payment record
79	      const { data: escrowData, error: escrowError } = await supabase
80	        .from("escrow_payments")
81	        .insert({
82	          campaign_id: campaign.id,
83	          application_id: application.id,
84	          brand_id: user.id,
85	          creator_id: application.creator_id,
86	          total_amount: totalAmount,
